final:
module max_finder (
    input [4:0] obf_A,
    input [4:0] B,
    input [4:0] C,
    output reg [4:0] max_out
);
    always @(*) begin
        if (obf_A >= B && obf_A >= C)
            max_out = obf_A;
        else if (B >= obf_A && B >= C)
            max_out = B;
        else
            max_out = C;
    end
endmodule
